// Build the licence-delivery email from the gateway's hand-off payload.
const d = $json.body || $json;
const features = Array.isArray(d.features) ? d.features.join(', ') : '';
const expires = d.expiresAt ? new Date(d.expiresAt).toUTCString() : 'no expiry';
const subject = 'Your OmniProject licence key';
const text = [
  `Hi ${d.customer || 'there'},`,
  '',
  'Thank you for your purchase. Your OmniProject licence key is:',
  '',
  d.licenseKey,
  '',
  `Tier:     ${d.tier}`,
  `Features: ${features}`,
  `Expires:  ${expires}`,
  '',
  'To activate: set this value as LICENSE_KEY in your OmniProject deployment',
  'environment, keep LICENSE_PUBLIC_KEY set to the issuer key, and restart.',
  '',
  'Guide: https://github.com/walshd1/Omniproject/blob/main/LICENSING.md',
].join('\n');
const html = `<p>Hi ${d.customer || 'there'},</p>`
  + `<p>Thank you for your purchase. Your OmniProject licence key is:</p>`
  + `<pre style="background:#111;color:#0f0;padding:12px;white-space:pre-wrap;word-break:break-all">${d.licenseKey}</pre>`
  + `<ul><li><b>Tier:</b> ${d.tier}</li><li><b>Features:</b> ${features}</li><li><b>Expires:</b> ${expires}</li></ul>`
  + `<p>To activate: set this value as <code>LICENSE_KEY</code> in your deployment (keep <code>LICENSE_PUBLIC_KEY</code> set) and restart.</p>`
  + `<p><a href="https://github.com/walshd1/Omniproject/blob/main/LICENSING.md">Activation guide</a></p>`;
return [{ json: { to: d.email, subject, text, html, customer: d.customer, tier: d.tier } }];
